cat ~/.openclaw/openclaw.json | python3 -c "
import sys,json
d=json.load(sys.stdin)
# Look for API keys or moltcn related config
def find_keys(obj, path=''):
    if isinstance(obj, dict):
        for k,v in obj.items():
            if 'key' in k.lower() or 'token' in k.lower() or 'secret' in k.lower() or 'molt' in k.lower():
                print(f'{path}.{k}: {str(v)[:50]}')
            find_keys(v, path+'.'+k)
    elif isinstance(obj, list):
        for i,v in enumerate(obj[:3]):
            find_keys(v, path+f'[{i}]')
find_keys(d)
" 2>/dev/null

